@typeparam TItem
@implements IAsyncDisposable

<div class="infinite-scroll-container">
    @foreach (var item in Items)
    {
        @ChildContent(item)
    }

    @if (HasMore)
    {
        <div @ref="_sentinelRef" class="infinite-scroll-sentinel">
            @if (_isLoading)
            {
                <div class="infinite-scroll-spinner" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            }
        </div>
    }
</div>

@code {
    private ElementReference _sentinelRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _observer;
    private DotNetObjectReference<InfiniteScrollList<TItem>>? _dotNetRef;
    private bool _isLoading;

    [Inject] private IJSRuntime JS { get; set; } = default!;

    /// <summary>The collection of items to display.</summary>
    [Parameter, EditorRequired] public IReadOnlyList<TItem> Items { get; set; } = [];

    /// <summary>Whether more items are available to load.</summary>
    [Parameter, EditorRequired] public bool HasMore { get; set; }

    /// <summary>Callback invoked when the user scrolls near the bottom.</summary>
    [Parameter, EditorRequired] public EventCallback OnLoadMore { get; set; }

    /// <summary>Template for rendering each item.</summary>
    [Parameter, EditorRequired] public RenderFragment<TItem> ChildContent { get; set; } = default!;

    /// <summary>
    /// How close to the sentinel (in CSS pixels) the viewport must be before loading triggers.
    /// Defaults to 100px.
    /// </summary>
    [Parameter] public int RootMarginPixels { get; set; } = 100;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-4fc8a3d7b364455dbe2d972ad1d24b30/Components/InfiniteScrollList.razor.js");
            _observer = await _module.InvokeAsync<IJSObjectReference>(
                "createObserver", _sentinelRef, _dotNetRef, RootMarginPixels);
        }
    }

    [JSInvokable]
    public async Task OnIntersecting()
    {
        if (_isLoading || !HasMore)
            return;

        _isLoading = true;
        StateHasChanged();

        await OnLoadMore.InvokeAsync();

        _isLoading = false;
        StateHasChanged();
    }

    public async ValueTask DisposeAsync()
    {
        if (_observer is not null)
        {
            await _observer.InvokeVoidAsync("disconnect");
            await _observer.DisposeAsync();
        }

        if (_module is not null)
            await _module.DisposeAsync();

        _dotNetRef?.Dispose();
    }
}

.infinite-scroll-container {
    overflow-y: auto;
    position: relative;
}

.infinite-scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 1rem 0;
    min-height: 1px; /* ensure the sentinel is observable even when empty */
}

.infinite-scroll-spinner {
    width: 2rem;
    height: 2rem;
    border: 0.25rem solid currentColor;
    border-right-color: transparent;
    border-radius: 50%;
    animation: infinite-scroll-spin 0.75s linear infinite;
}

@keyframes infinite-scroll-spin {
    to {
        transform: rotate(360deg);
    }
}

/**
 * Creates an IntersectionObserver that calls back into .NET when the
 * sentinel element becomes visible inside its scrollable ancestor.
 *
 * @param {Element} sentinel  - The DOM element to observe.
 * @param {object}  dotNetRef - A DotNetObjectReference for JS-interop callbacks.
 * @param {number}  rootMarginPx - Extra margin (px) to trigger loading before
 *                                 the sentinel is fully in view.
 * @returns {IntersectionObserver} The observer instance (so Blazor can call disconnect).
 */
export function createObserver(sentinel, dotNetRef, rootMarginPx) {
    const observer = new IntersectionObserver(
        (entries) => {
            for (const entry of entries) {
                if (entry.isIntersecting) {
                    dotNetRef.invokeMethodAsync("OnIntersecting");
                }
            }
        },
        {
            rootMargin: `0px 0px ${rootMarginPx}px 0px`,
        }
    );

    observer.observe(sentinel);
    return observer;
}

