/**
 * Creates an IntersectionObserver that calls back into .NET when the
 * sentinel element becomes visible inside its scrollable ancestor.
 *
 * @param {Element} sentinel  - The DOM element to observe.
 * @param {object}  dotNetRef - A DotNetObjectReference for JS-interop callbacks.
 * @param {number}  rootMarginPx - Extra margin (px) to trigger loading before
 *                                 the sentinel is fully in view.
 * @returns {IntersectionObserver} The observer instance (so Blazor can call disconnect).
 */
export function createObserver(sentinel, dotNetRef, rootMarginPx) {
    const observer = new IntersectionObserver(
        (entries) => {
            for (const entry of entries) {
                if (entry.isIntersecting) {
                    dotNetRef.invokeMethodAsync("OnIntersecting");
                }
            }
        },
        {
            rootMargin: `0px 0px ${rootMarginPx}px 0px`,
        }
    );

    observer.observe(sentinel);
    return observer;
}

